// Gemini vision judge for the crayon renderer. Feeds real-crayon reference
// photos (out/ref-*.png, generated by gen-refs.mjs) plus my rendered variant
// scenes (out/v<N>-*.png) to gemini-2.5-flash and asks for a scored, specific
// critique — an automated adversarial reviewer for the design loop the user
// asked for. Scores + concrete parameter suggestions come back as JSON.
//
//   node crayon-lab/judge.mjs --variant=12
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { GoogleGenAI } from '@google/genai';

const HERE = dirname(fileURLToPath(import.meta.url));
const OUT = join(HERE, 'out');
const args = process.argv.slice(2);
const variant = Number(
  (args.find((a) => a.startsWith('--variant=')) || '--variant=12').split('=')[1]
);

const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY });
const img = (name) => ({
  inlineData: { mimeType: 'image/png', data: readFileSync(join(OUT, name)).toString('base64') },
});

const prompt = `You are a demanding art-tools reviewer judging a digital "crayon" brush for a
toddler drawing app. The goal: it must look like a real wax crayon on textured paper.

I will give you, in order:
  1. REFERENCE-SINGLE: a photo of a REAL single crayon stroke.
  2. REFERENCE-OVERLAP: a photo of REAL crayon where two same-colour strokes cross.
  3. MINE-SINGLE: my brush, one stroke.
  4. MINE-DOUBLED: my brush, the same stroke drawn twice.
  5. MINE-CROSS: my brush, two same-colour strokes crossing.

Judge MINE against the references on these axes (score each 1-10, 10 = indistinguishable
from real crayon):
  - waxy: does it read as waxy crayon vs a flat marker/pen?
  - grain: is the texture a FINE paper-tooth speckle (good) or coarse/gritty/noisy (bad)?
  - containment: is the grain contained to the stroke, or does it spray/starburst past the edge (bad)?
  - buildup: comparing MINE-SINGLE vs MINE-DOUBLED and the crossing in MINE-CROSS, does an
    overlapping second pass read DENSER / more filled-in at the SAME hue (good, like the
    reference overlap), rather than unchanged, or shifted/darkened to a different colour (bad)?

Be harsh and specific. Then give concrete, actionable suggestions (e.g. "reduce body coverage
so more tooth shows", "grain too coarse, shrink cell size", "edge sprays, clamp tighter").

Respond ONLY with minified JSON:
{"waxy":n,"grain":n,"containment":n,"buildup":n,"overall":n,"critique":"2-3 sentences","suggestions":["...","..."]}`;

const contents = [
  { text: prompt },
  { text: '1. REFERENCE-SINGLE:' },
  img('ref-single.png'),
  { text: '2. REFERENCE-OVERLAP:' },
  img('ref-overlap.png'),
  { text: '3. MINE-SINGLE:' },
  img(`v${variant}-single.png`),
  { text: '4. MINE-DOUBLED:' },
  img(`v${variant}-doubled.png`),
  { text: '5. MINE-CROSS:' },
  img(`v${variant}-cross.png`),
];

const r = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents });
const text = (r.text || '').trim();
const m = text.match(/\{[\s\S]*\}/);
console.log(m ? JSON.stringify(JSON.parse(m[0]), null, 2) : text);
